def _continuous_numpy_fallback(
    illuminance_lux: float,
    setpoint_lux: float,
    min_power_fraction: float,
    min_light_fraction: float,
) -> float:
    if setpoint_lux <= 0.0:
        return 1.0
    illum = max(0.0, illuminance_lux)
    fl = (setpoint_lux - illum) / setpoint_lux
    fl = max(0.0, min(1.0, fl))
    if fl >= 1.0:
        return 1.0
    if fl <= 0.0:
        return float(min_power_fraction)
    denom = 1.0 - min_light_fraction
    if denom <= 0.0:
        return float(min_power_fraction)
    if fl <= min_light_fraction:
        return float(min_power_fraction)
    fp = (fl + (1.0 - fl) * min_power_fraction - min_light_fraction) / denom
    fp = max(min_power_fraction, min(1.0, fp))
    return float(fp)

