FC_ABS = 0
FC_CEILING = 6
FC_COS = 12
FC_EXP = 10
FC_FLOOR = 7
FC_INT = 5
FC_LN = 9
FC_MAX = 3
FC_MIN = 4
FC_MOD = 2
FC_ROUND = 1
FC_SIN = 11
FC_SQRT = 8
FC_TAN = 13

import math

def _numpy_eval_one(code: int, x: float, y: float) -> float:
    nan = float("nan")
    if code == FC_ABS:
        return abs(x)
    if code == FC_ROUND:
        return float(round(x))
    if code == FC_MOD:
        if y == 0.0:
            return nan
        return x - y * math.floor(x / y)
    if code == FC_MAX:
        return max(x, y)
    if code == FC_MIN:
        return min(x, y)
    if code == FC_INT:
        return math.trunc(x)
    if code == FC_CEILING:
        return math.ceil(x)
    if code == FC_FLOOR:
        return math.floor(x)
    if code == FC_SQRT:
        return nan if x < 0.0 else math.sqrt(x)
    if code == FC_LN:
        return nan if x <= 0.0 else math.log(x)
    if code == FC_EXP:
        return math.exp(x)
    if code == FC_SIN:
        return math.sin(x)
    if code == FC_COS:
        return math.cos(x)
    if code == FC_TAN:
        return math.tan(x)
    return nan

def _numpy_counterflow_eff(ntu: float, c_ratio: float) -> float:
    delta = abs(1.0 - c_ratio)
    if delta < 1e-6:
        return ntu / (1.0 + ntu)
    import math
    exp_term = math.exp(-ntu * (1.0 - c_ratio))
    return (1.0 - exp_term) / (1.0 - c_ratio * exp_term)

_TARP_ENHANCED_DEN = 7.283
_TARP_ENHANCED_NUM = 9.482
_TARP_REDUCED_DEN = 1.382
_TARP_REDUCED_NUM = 1.81
_TARP_VERTICAL_COEF = 1.31
_TARP_VERTICAL_TOL_DEG = 2.0

import math

def _py_h_natural_tarp(t_surf: float, t_air: float, tilt_deg: float) -> float:
    dt = t_surf - t_air
    abs_dt = abs(dt)
    if abs_dt == 0.0:
        return 0.0
    cbrt = abs_dt ** (1.0 / 3.0)
    if abs(tilt_deg - 90.0) < _TARP_VERTICAL_TOL_DEG:
        return _TARP_VERTICAL_COEF * cbrt
    cos_tilt = math.cos(math.radians(tilt_deg))
    abs_cos = abs(cos_tilt)
    if (dt * cos_tilt) > 0.0:
        return _TARP_ENHANCED_NUM * cbrt / (_TARP_ENHANCED_DEN - abs_cos)
    return _TARP_REDUCED_NUM * cbrt / (_TARP_REDUCED_DEN + abs_cos)

