def _np_ppd_from_pmv(pmv: float) -> float:
    pmv2 = pmv * pmv
    ppd = 100.0 - 95.0 * math.exp(-0.03353 * pmv2 * pmv2 - 0.2179 * pmv2)
    return max(5.0, min(100.0, ppd))

def _np_bulk_fraction(
    heating_w: float,
    cooling_w: float,
    h_total_cap: float,
    c_total_cap: float,
) -> float:
    h_plr = min(max(heating_w, 0.0) / h_total_cap, 1.0) if h_total_cap > 0.0 else 0.0
    c_plr = min(max(cooling_w, 0.0) / c_total_cap, 1.0) if c_total_cap > 0.0 else 0.0
    return max(h_plr, c_plr)

