def _smooth_ramp(value: float, threshold: float, half_width: float, ascending: bool) -> float:
    if half_width <= 0.0:
        return (1.0 if value >= threshold else 0.0) if ascending else (1.0 if value <= threshold else 0.0)
    delta = value - threshold
    if ascending:
        if delta <= -half_width:
            return 0.0
        if delta >= half_width:
            return 1.0
        return 0.5 + 0.5 * (delta / half_width)
    # descending mirror
    if delta >= half_width:
        return 0.0
    if delta <= -half_width:
        return 1.0
    return 0.5 - 0.5 * (delta / half_width)

