def frame_area_m2(
    window_width_m: float,
    window_height_m: float,
    frame_width_m: float,
) -> float:
    if frame_width_m <= 0.0:
        return 0.0
    glazed_w = window_width_m - 2.0 * frame_width_m
    glazed_h = window_height_m - 2.0 * frame_width_m
    if glazed_w <= 0.0 or glazed_h <= 0.0:
        # The frame consumes the entire opening; treat the whole
        # rectangle as frame area.
        return max(0.0, window_width_m * window_height_m)
    return window_width_m * window_height_m - glazed_w * glazed_h

def assembly_u_factor_w_m2k(
    cog_u_w_m2k: float,
    glazed_area_m2: float,
    frame_u_w_m2k: float,
    frame_area_m2_value: float,
    frame_edge_ratio: float = 1.0,
    frame_edge_area_m2: float = 0.0,
) -> float:
    if frame_area_m2_value <= 0.0:
        return cog_u_w_m2k
    total_area = glazed_area_m2 + frame_area_m2_value
    if total_area <= 0.0:
        raise ValueError(
            f"assembly_u_factor: non-positive total area "
            f"(glazed={glazed_area_m2}, frame={frame_area_m2_value})"
        )
    ua = cog_u_w_m2k * glazed_area_m2 + frame_u_w_m2k * frame_area_m2_value
    if frame_edge_area_m2 > 0.0 and frame_edge_ratio != 1.0:
        ua += (frame_edge_ratio - 1.0) * cog_u_w_m2k * frame_edge_area_m2
    return ua / total_area

